# frozen_string_literal: true

require "concurrent/executor/fixed_thread_pool"

module ActiveSupport
  module Testing
    class Parallelization # :nodoc:
      # Thread pool executor using a test distributor strategy.
      # Provides the same interface as Minitest::Parallel::Executor but
      # with configurable distribution (round robin vs work stealing).
      class ThreadPoolExecutor
        attr_reader :size

        def initialize(size:, distributor:)
          @size = size
          @distributor = distributor
          @pool = Concurrent::FixedThreadPool.new(size, fallback_policy: :abort)
        end

        def start
          size.times do |worker_id|
            @pool.post { worker_loop(worker_id) }
          end
        end

        def <<(work)
          @distributor.add_test(work)
        end

        def shutdown
          @distributor.close
          @pool.shutdown
          @pool.wait_for_termination
        end

        private
          def worker_loop(worker_id)
            while job = @distributor.take(worker_id: worker_id)
              klass, method, reporter = job

              reporter.synchronize { reporter.prerecord klass, method }
              result = if Minitest.respond_to? :run_one_method then
                Minitest.run_one_method klass, method
              else
                klass.new(method).run
              end
              reporter.synchronize { reporter.record result }
            end
          end
      end
    end
  end
end

require 'thread'

module Flipper
  # Internal: Used to store registry of groups by name.
  class Registry
    include Enumerable

    class Error < StandardError; end
    class DuplicateKey < Error; end

    class KeyNotFound < Error
      # Public: The key that was not found
      attr_reader :key

      def initialize(key)
        @key = key
        super("Key #{key.inspect} not found")
      end
    end

    def initialize(source = {})
      @mutex = Mutex.new
      @source = source
    end

    def keys
      @mutex.synchronize { @source.keys }
    end

    def values
      @mutex.synchronize { @source.values }
    end

    def add(key, value)
      key = key.to_sym

      @mutex.synchronize do
        if @source[key]
          raise DuplicateKey, "#{key} is already registered"
        else
          @source[key] = value
        end
      end
    end

    def get(key)
      key = key.to_sym
      @mutex.synchronize do
        @source[key]
      end
    end

    def key?(key)
      key = key.to_sym
      @mutex.synchronize do
        @source.key?(key)
      end
    end

    def each(&block)
      @mutex.synchronize { @source.dup }.each(&block)
    end

    def clear
      @mutex.synchronize { @source.clear }
    end
  end
end

module Flipper
  module Adapters
    class DualWrite
      include ::Flipper::Adapter

      attr_reader :local, :remote

      # Public: Build a new sync instance.
      #
      # local - The local flipper adapter that should serve reads.
      # remote - The remote flipper adapter that writes should go to first (in
      #          addition to the local adapter).
      def initialize(local, remote, options = {})
        @local = local
        @remote = remote
      end

      def adapter_stack
        "#{name}(local: #{@local.adapter_stack}, remote: #{@remote.adapter_stack})"
      end

      def features
        @local.features
      end

      def get(feature)
        @local.get(feature)
      end

      def get_multi(features)
        @local.get_multi(features)
      end

      def get_all(**kwargs)
        @local.get_all(**kwargs)
      end

      def add(feature)
        @remote.add(feature).tap { @local.add(feature) }
      end

      def remove(feature)
        @remote.remove(feature).tap { @local.remove(feature) }
      end

      def clear(feature)
        @remote.clear(feature).tap { @local.clear(feature) }
      end

      def enable(feature, gate, thing)
        @remote.enable(feature, gate, thing).tap do
          @local.enable(feature, gate, thing)
        end
      end

      def disable(feature, gate, thing)
        @remote.disable(feature, gate, thing).tap do
          @local.disable(feature, gate, thing)
        end
      end
    end
  end
end

module Flipper
  module Adapters
    class Failsafe
      include ::Flipper::Adapter

      # Public: Build a new Failsafe instance.
      #
      # adapter   - Flipper adapter to guard.
      # options   - Hash of options:
      #             :errors - Array of exception types for which to fail safe

      def initialize(adapter, options = {})
        @adapter = adapter
        @errors = options.fetch(:errors, [StandardError])
      end

      def features
        @adapter.features
      rescue *@errors
        Set.new
      end

      def add(feature)
        @adapter.add(feature)
      rescue *@errors
        false
      end

      def remove(feature)
        @adapter.remove(feature)
      rescue *@errors
        false
      end

      def clear(feature)
        @adapter.clear(feature)
      rescue *@errors
        false
      end

      def get(feature)
        @adapter.get(feature)
      rescue *@errors
        {}
      end

      def get_multi(features)
        @adapter.get_multi(features)
      rescue *@errors
        {}
      end

      def get_all(**kwargs)
        @adapter.get_all(**kwargs)
      rescue *@errors
        {}
      end

      def enable(feature, gate, thing)
        @adapter.enable(feature, gate, thing)
      rescue *@errors
        false
      end

      def disable(feature, gate, thing)
        @adapter.disable(feature, gate, thing)
      rescue *@errors
        false
      end
    end
  end
end
